<?php
namespace App\Models\Sales; use App\Models\Inventory\Item;use App\Models\Inventory\ItemBatch;use App\Models\Inventory\Uom;use Illuminate\Database\Eloquent\Model;
class ShipmentLine extends Model{protected $fillable=['shipment_id','sale_line_id','item_id','batch_id','facility_scheme_id','uom_id','qty_ordered','qty_already_shipped','qty_shipped','qty_base','notes']; protected $casts=['qty_ordered'=>'decimal:4','qty_already_shipped'=>'decimal:4','qty_shipped'=>'decimal:4','qty_base'=>'decimal:4']; public function shipment(){return $this->belongsTo(Shipment::class);}public function saleLine(){return $this->belongsTo(SalesLine::class,'sale_line_id');}public function item(){return $this->belongsTo(Item::class);}public function batch(){return $this->belongsTo(ItemBatch::class);}public function uom(){return $this->belongsTo(Uom::class);} }
